sed -i '/- name: Install Playwright (browsers + deps)/i \    - name: Install dfx (Internet Computer SDK)\n      run: |\n        DFXVM_INIT_YES=true DFX_VERSION=0.30.2 sh -ci "$(curl -fsSL https://internetcomputer.org/install.sh)"\n        echo "$HOME/.local/share/dfx/bin" >> $GITHUB_PATH\n\n    - name: Install mops (Motoko package manager)\n      run: npm install -g ic-mops@2.4.0\n\n    - name: Install Motoko dependencies\n      run: mops install\n\n    - name: Start DFX and Deploy backend\n      run: |\n        dfx start --background\n        DFX_WARNING=-mainnet_plaintext_identity dfx deploy backend\n' .github/workflows/node.js.yml
